Event = namedtuple('Event', ['stream_id', 'version', 'event_type', 'payload', 'timestamp'])

class VersionConflict(Exception):
    """Raised when an append operation fails due to incorrect expected version."""
    pass

class EventStore:
    def __init__(self):
        # { stream_id: list[Event] }
        self._streams = {}

    def _get_stream(self, stream_id: str) -> list[Event]:
        if stream_id not in self._streams:
            self._streams[stream_id] = []
        return self._streams[stream_id]

    def append(self, stream_id: str, event_type: str, payload: dict,
               expected_version: int = -1) -> Event:
        event_list = self._get_stream(stream_id)
        current_version = self.stream_version(stream_id)

        if expected_version != -1 and current_version != expected_version:
            raise VersionConflict(f"Expected version {expected_version}, but found {current_version}")

        # Determine the new version number (0-indexed)
        new_version = len(event_list)

        new_event = Event(
            stream_id=stream_id,
            version=new_version,
            event_type=event_type,
            payload=payload,
            timestamp=time.time()
        )
        event_list.append(new_event)
        return new_event

    def load(self, stream_id: str) -> list[Event]:
        return self._streams.get(stream_id, []).copy()

    def stream_version(self, stream_id: str) -> int:
        """Returns the current version (count of events) or -1 if not found."""
        if stream_id not in self._streams:
            return -1
        return len(self._streams[stream_id])

